  1	import { Alert, Button, Divider, FormHelperText } from '@patternfly/react-core';
  2	import { MinusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/minus-circle-icon';
  3	import { PlusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/plus-circle-icon';
  4	import {
  5	  ArrayFieldTemplateProps,
  6	  DescriptionFieldProps,
  7	  FieldTemplateProps,
  8	  getSchemaType,
  9	  getUiOptions,
 10	  ObjectFieldTemplateProps
 11	} from '@rjsf/utils';
 12	import * as _ from 'lodash';
 13	import * as React from 'react';
 14	import { useTranslation } from 'react-i18next';
 15	import { jsonSchemaGroupTypes } from './const';
 16	import { DescriptionField, FieldSet, FormField } from './fields';
 17	import { UiSchemaOptionsWithDependency } from './types';
 18	import { useSchemaLabel } from './utils';
 19	
 20	export const AtomicFieldTemplate: React.FC<FieldTemplateProps> = ({
 21	  children,
 22	  id,
 23	  label,
 24	  rawErrors,
 25	  description,
 26	  required,
 27	  schema,
 28	  uiSchema
 29	}) => {
 30	  // put description before or after children based on widget type
 31	  const descriptionFirst = uiSchema?.['ui:descriptionFirst'] === 'true';
 32	  return (
 33	    <FormField id={id} defaultLabel={label} required={required || false} schema={schema} uiSchema={uiSchema || {}}>
 34	      {descriptionFirst && description}
 35	      {children}
 36	      {!descriptionFirst && description}
 37	      {!_.isEmpty(rawErrors) && (
 38	        <>
 39	          {_.map(rawErrors, error => (
 40	            <FormHelperText key={error}>{_.capitalize(error)}</FormHelperText>
 41	          ))}
 42	        </>
 43	      )}
 44	    </FormField>
 45	  );
 46	};
 47	
 48	export const DescriptionFieldTemplate: React.FC<DescriptionFieldProps> = props => {
 49	  return <DescriptionField {...props} />;
 50	};
 51	
 52	export const FieldTemplate: React.FC<FieldTemplateProps> = props => {
 53	  const { id, hidden, schema = {}, children, uiSchema = {}, formContext = {} } = props;
 54	  const type = getSchemaType(schema);
 55	  const [dependencyMet, setDependencyMet] = React.useState(true);
 56	  React.useEffect(() => {
 57	    const { dependency } = getUiOptions(uiSchema ?? {}) as UiSchemaOptionsWithDependency; // Type defs for this function are awful
 58	    if (dependency) {
 59	      setDependencyMet(() => {
 60	        let val = _.get(formContext.formData ?? {}, ['spec'], '');
 61	        dependency.controlFieldPath.forEach(path => {
 62	          val = _.get(val, [path], '');
 63	          if (Array.isArray(val)) {
 64	            // retreive id from path
 65	            // example root_spec_exporters_4_ipfix will return 4
 66	            val = val[Number(id.replace(/\D/g, ''))];
 67	          }
 68	        });
 69	
 70	        return dependency?.controlFieldValue === String(val);
 71	      });
 72	    }
 73	  }, [uiSchema, formContext, id]);
 74	
 75	  if (hidden || !dependencyMet) {
 76	    return null;
 77	  }
 78	  const isGroup = jsonSchemaGroupTypes.includes(String(type));
 79	  return isGroup ? children : <AtomicFieldTemplate {...props} />;
 80	};
 81	
 82	export const ObjectFieldTemplate: React.FC<ObjectFieldTemplateProps> = props => {
 83	  const { idSchema, properties, required, schema, title, uiSchema } = props;
 84	  const { flat } = getUiOptions(uiSchema ?? {});
 85	  if (flat === 'true') {
 86	    return <>{_.map(properties || [], p => p.content)}</>;
 87	  }
 88	
 89	  return (
 90	    <FieldSet defaultLabel={title} idSchema={idSchema} required={required} schema={schema} uiSchema={uiSchema}>
 91	      <div className="co-dynamic-form__field-group-content">
 92	        {properties?.length > 0 && _.map(properties, p => p.content)}
 93	      </div>
 94	    </FieldSet>
 95	  );
 96	};
 97	
 98	export const ArrayFieldTemplate: React.FC<ArrayFieldTemplateProps> = ({
 99	  idSchema,
100	  items,
101	  onAddClick,
102	  required,
103	  schema,
104	  title,
105	  uiSchema
106	}) => {
107	  const { t } = useTranslation('plugin__netobserv-plugin');
108	  const [, label] = useSchemaLabel(schema, uiSchema || {}, title ?? 'Items');
109	  return (
110	    <FieldSet defaultLabel={label} idSchema={idSchema} required={required} schema={schema} uiSchema={uiSchema}>
111	      {_.map(items ?? [], item => {
112	        return (
113	          <div className="co-dynamic-form__array-field-group-item" key={item.key}>
114	            {item.index > 0 && <Divider className="co-divider" />}
115	            {item.hasRemove && (
116	              <div className="row co-dynamic-form__array-field-group-remove">
117	                <Button
118	                  icon={<MinusCircleIcon className="co-icon-space-r" />}
119	                  id={`${item.key}_remove-btn`}
120	                  type="button"
121	                  onClick={item.onDropIndexClick(item.index)}
122	                  variant="link"
123	                >
124	                  {t('Remove {{singularLabel}}', { singularLabel: label })}
125	                </Button>
126	              </div>
127	            )}
128	            {item.children}
129	          </div>
130	        );
131	      })}
132	      <div className="row">
133	        <Button
134	          icon={<PlusCircleIcon className="co-icon-space-r" />}
135	          id={`${idSchema.$id}_add-btn`}
136	          type="button"
137	          onClick={onAddClick}
138	          variant="link"
139	        >
140	          {t('Add {{singularLabel}}', { singularLabel: label })}
141	        </Button>
142	      </div>
143	    </FieldSet>
144	  );
145	};
146	
147	export const ErrorTemplate: React.FC<{ errors: string[] }> = ({ errors }) => {
148	  const { t } = useTranslation('plugin__netobserv-plugin');
149	  return (
150	    <Alert isInline className="co-alert co-break-word co-alert--scrollable" variant="danger" title={t('Error')}>
151	      {t('Fix the following errors:')}
152	      <ul>
153	        {_.map(errors, error => (
154	          <li key={error}>{error}</li>
155	        ))}
156	      </ul>
157	    </Alert>
158	  );
159	};
160	
161	export default {
162	  FieldTemplate,
163	  DescriptionFieldTemplate,
164	  ArrayFieldTemplate,
165	  ObjectFieldTemplate
166	};

